import React, { useState, useEffect, useCallback } from 'react';
import './CreateCombinedMaterial.css';

const CombinedMaterialInputForm = ({
    onClose,
    fetchAPI,
    apiBaseUrl,
    onMaterialAdded,
}) => {
    const initialComboMat = {
        name: '',
        description: '',
        submaterials: [],
    };

    const [comboMat, setComboMat] = useState(initialComboMat);
    const [error, setError] = useState(null);
    const [materials, setMaterials] = useState([]);
    const [submaterials, setSubmaterials] = useState([]);

    const fetchData = useCallback(async () => {
        try {
            const MaterialData = await fetchAPI(`${apiBaseUrl}/materiallist`);
            setMaterials(MaterialData);
        } catch (error) {
            setError(error.message);
        }
    }, [fetchAPI, apiBaseUrl]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setComboMat((prevComboMat) => ({
            ...prevComboMat,
            [name]: value,
        }));
    };

    const handleSubmaterialChange = (index, field, value) => {
        const updatedSubmaterials = [...submaterials];
        updatedSubmaterials[index][field] = value;
        setSubmaterials(updatedSubmaterials); // Update the submaterials directly
    };

    const saveCombinedMaterial = async () => {
        try {
            const combinedMaterialResponse = await fetchAPI(`${apiBaseUrl}/combinedMaterials`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    name: comboMat.name,
                    description: comboMat.description,
                }),
            });

            if (!combinedMaterialResponse.ok) {
                const responseData = await combinedMaterialResponse.json();
                alert(`Error creating combined material: ${responseData.error || 'Unknown error'}`);
                return;
            }

            const combinedMaterialData = await combinedMaterialResponse.json();
            const combined_material_id = combinedMaterialData.id; // Ensure this matches the actual response structure

            // Prepare submaterials payload with the combined material ID
            const submaterialsPayload = submaterials.map(submaterial => ({
                combined_material_id: combined_material_id,
                material_id: submaterial.materialId,
                multiplier: submaterial.multiplier,
            }));

            const submaterialsResponse = await fetchAPI(`${apiBaseUrl}/submaterials`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({ submaterials: submaterialsPayload }), // Adjust based on your API
            });

            if (!submaterialsResponse.ok) {
                const responseData = await submaterialsResponse.json();
                alert(`Error creating submaterials: ${responseData.error}`);
                return;
            }

            alert('Combined material and submaterials saved successfully!');
            setComboMat(initialComboMat); // Reset the form
            setSubmaterials([]); // Reset submaterials
            onMaterialAdded();
            onClose();
        } catch (error) {
            alert(`Error: ${error.message}`);
        }
    };

    const addMaterial = () => {
        setSubmaterials([...submaterials, { materialId: '', multiplier: 1, unitPrice: 0 }]);
    };

    const removeMaterial = (index) => {
        setSubmaterials(submaterials.filter((_, i) => i !== index));
    };

    if (error) return <div>Error: {error}</div>;

    // ... (Rest of your component's return statement)
};

export default CombinedMaterialInputForm;
